import{_ as i,o as s,c as o,ag as r}from"./chunks/framework.DtEl18Xn.js";const n="/getbiji-docs-v3/images/SLI3b0H0eoKbbexQz7PcHxCunHc.png",l="/getbiji-docs-v3/images/PP1xbChUooLKKxx0pQMcvHq4nsg.png",a="/getbiji-docs-v3/images/Uj69bJZF2oSVyrxFr9wcDkwCnfd.png",g="/getbiji-docs-v3/images/C7sHbJVzMoV8smxbLO9cEbp6nGg.png",e="/getbiji-docs-v3/images/WRlnbNdXeozuu7xjFSvcsiJ2nhg.png",u=JSON.parse('{"title":"拍几张照-秒变笔记","description":"","frontmatter":{"title":"拍几张照-秒变笔记","category":" 如何快速上手记笔记","lastUpdated":"2026-03-14T14:54:18.466Z"},"headers":[],"relativePath":"-如何快速上手记笔记/拍几张照-秒变笔记.md","filePath":"-如何快速上手记笔记/拍几张照-秒变笔记.md"}'),p={name:"-如何快速上手记笔记/拍几张照-秒变笔记.md"};function _(c,t,m,d,b,P){return s(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="拍几张照-秒变笔记" tabindex="-1">拍几张照-秒变笔记 <a class="header-anchor" href="#拍几张照-秒变笔记" aria-label="Permalink to &quot;拍几张照-秒变笔记&quot;">​</a></h1><p>🖼️ <strong>拍<strong><strong>几</strong></strong>张，看懂一切——AI 图片笔记把照片秒变条理清晰的笔记！</strong></p><p>再也不用在白板、PPT 和信息图之间疯狂截图＋打字；轻轻按下快门，复杂视觉内容瞬间提炼为可编辑、可搜索、结构化的文字。</p><p><strong>适用****场景</strong></p><ul><li><strong>课堂 &amp; 培训</strong>：拍下投影 PPT，一秒生成讲义笔记，自动理解核心知识要点</li><li><strong>会议白板</strong>：涂满箭头的 brainstorming 不怕糊；AI 识别流程图关系，转成清单</li><li><strong>读书摘录</strong>：对着纸质书拍几页，立刻得到排版工整的原文摘录</li><li><strong>展览说明牌</strong>：漫步学术年会或博物馆，拍张信息海报就拿到结构化解读</li><li><strong>日常饮食</strong>：把日常每一餐拍进手机，自动分析这一餐的食材和总卡路里</li><li><strong>旅行攻略</strong>：拍机场地图、地铁线路图，AI 自动把站点信息转成可搜的文本</li><li><strong>账单 &amp; 收据</strong>：一键识别金额、日期、商户并分类，月底记账不再翻票根</li><li>**教科书里的公式：**包含数学公式、化学方程式，LaTeX 形式输出，可直接贴进论文或作业</li><li>**程序代码：**拍下屏幕或书本上的代码片段，AI 自动识别语言并转为可复制的文本格式</li><li><strong>数据表格</strong>：手机对准报表、统计图表一拍，瞬间转换为可编辑的结构化数据</li></ul><h1 id="app-端使用" tabindex="-1">APP 端使用 <a class="header-anchor" href="#app-端使用" aria-label="Permalink to &quot;APP 端使用&quot;">​</a></h1><ol><li>打开 App，点击首页底部 + 号，选择**「拍照」<strong>或</strong>「上传图片」**</li><li>首次使用时，授权允许相册使用权限</li><li>可选多张图片上传，一次可上传10张图</li><li>选择识图模式**「智能总结」、「全文提取」或 **自定义整理风格</li><li>**智能总结：**AI自动选择最佳总结方式，一键把照片“嚼碎”成条理清晰的笔记，90 %的场景直接选它就够。</li><li>**全文提取：**智能OCR，逐字还原，细节一条不漏，比 OCR 更懂逻辑，把图片里的每一个字、每一条数据，<strong>原汁原味且成体系</strong> 地搬进笔记。</li><li>笔记生成后，双击文本区域，可对笔记进一步编辑；</li><li>需要分享时，点击右上角「... <strong>更多」</strong></li><li>可以生成笔记海报进行分享</li><li>也可以导出 DOCX / PDF 文件发给好友</li></ol><p><img src="'+n+'" alt=""></p><p><img src="'+l+'" alt=""></p><p><img src="'+a+'" alt=""></p><p><img src="'+g+'" alt=""></p><p><img src="'+e+'" alt=""></p>',12)])])}const x=i(p,[["render",_]]);export{u as __pageData,x as default};
